   169→	httpResp, err := m.client.Do(httpReq)
   170→	if err != nil {
   171→		return nil, fmt.Errorf("openai: http request: %w", err)
   172→	}
   173→	defer httpResp.Body.Close()
   174→
   175→	respBody, err := io.ReadAll(httpResp.Body)
   176→	if err != nil {
   177→		return nil, fmt.Errorf("openai: read response: %w", err)
   178→	}
   179→
   180→	if httpResp.StatusCode != http.StatusOK {
   181→		return nil, fmt.Errorf("openai: API returned status %d: %s", httpResp.StatusCode, string(respBody))
   182→	}
   183→
   184→	var chatResp chatResponse
   185→	if err := json.Unmarshal(respBody, &chatResp); err != nil {
   186→		return nil, fmt.Errorf("openai: unmarshal response: %w", err)
   187→	}
   188→
   189→	if chatResp.Error != nil {
   190→		return nil, fmt.Errorf("openai: API error: %s (type=%s, code=%s)",
   191→			chatResp.Error.Message, chatResp.Error.Type, chatResp.Error.Code)
   192→	}
   193→
   194→	return convertResponse(&chatResp), nil
   195→}
