   197→// convertContents transforms ADK genai.Content messages into OpenAI chat messages.
   198→func convertContents(req *model.LLMRequest) []chatMessage {
   199→	var msgs []chatMessage
   200→
   201→	// System instruction.
   202→	if req.Config != nil && req.Config.SystemInstruction != nil {
   203→		var text string
   204→		for _, p := range req.Config.SystemInstruction.Parts {
   205→			if p.Text != "" {
   206→				text += p.Text
   207→			}
   208→		}
   209→		if text != "" {
   210→			msgs = append(msgs, chatMessage{Role: "system", Content: text})
   211→		}
   212→	}
   213→
   214→	// Conversation contents.
   215→	for _, c := range req.Contents {
   216→		role := mapRole(c.Role)
   217→
   218→		// Check each part: could be text, function_call, or function_response.
   219→		for _, p := range c.Parts {
   220→			switch {
   221→			case p.FunctionCall != nil:
   222→				argsJSON, _ := json.Marshal(p.FunctionCall.Args)
   223→				msgs = append(msgs, chatMessage{
   224→					Role: "assistant",
   225→					ToolCalls: []toolCall{{
   226→						ID:   p.FunctionCall.ID,
   227→						Type: "function",
   228→						Function: functionCall{
   229→							Name:      p.FunctionCall.Name,
   230→							Arguments: string(argsJSON),
   231→						},
   232→					}},
   233→				})
   234→			case p.FunctionResponse != nil:
   235→				respJSON, _ := json.Marshal(p.FunctionResponse.Response)
   236→				msgs = append(msgs, chatMessage{
   237→					Role:       "tool",
   238→					Content:    string(respJSON),
   239→					ToolCallID: p.FunctionResponse.ID,
   240→				})
   241→			case p.Text != "":
   242→				msgs = append(msgs, chatMessage{Role: role, Content: p.Text})
   243→			}
   244→		}
   245→	}
   246→
   247→	// Merge consecutive assistant messages with tool_calls.
   248→	msgs = mergeAssistantToolCalls(msgs)
   249→
   250→	return msgs
   251→}
   252→
   253→// mergeAssistantToolCalls combines adjacent assistant messages that each have
   254→// tool_calls into a single message, as OpenAI expects multiple tool_calls in
   255→// one message rather than separate messages.
   256→func mergeAssistantToolCalls(msgs []chatMessage) []chatMessage {
   257→	if len(msgs) == 0 {
   258→		return msgs
   259→	}
   260→	var merged []chatMessage
   261→	for _, msg := range msgs {
   262→		if msg.Role == "assistant" && len(msg.ToolCalls) > 0 && len(merged) > 0 {
   263→			prev := &merged[len(merged)-1]
   264→			if prev.Role == "assistant" && len(prev.ToolCalls) > 0 {
   265→				prev.ToolCalls = append(prev.ToolCalls, msg.ToolCalls...)
   266→				continue
   267→			}
   268→		}
   269→		merged = append(merged, msg)
   270→	}
   271→	return merged
   272→}
