   274→// convertTools transforms ADK genai.Tool definitions into OpenAI tool format.
   275→func convertTools(req *model.LLMRequest) []chatTool {
   276→	if req.Config == nil || len(req.Config.Tools) == 0 {
   277→		return nil
   278→	}
   279→
   280→	var tools []chatTool
   281→	for _, t := range req.Config.Tools {
   282→		for _, fd := range t.FunctionDeclarations {
   283→			ct := chatTool{
   284→				Type: "function",
   285→				Function: chatFunction{
   286→					Name:        fd.Name,
   287→					Description: fd.Description,
   288→				},
   289→			}
   290→			if fd.Parameters != nil {
   291→				ct.Function.Parameters = schemaToMap(fd.Parameters)
   292→			}
   293→			tools = append(tools, ct)
   294→		}
   295→	}
   296→	return tools
   297→}
   298→
   299→// schemaToMap converts a genai.Schema to a JSON-serialisable map that matches
   300→// the OpenAI function parameters format (JSON Schema).
   301→func schemaToMap(s *genai.Schema) map[string]any {
   302→	m := map[string]any{}
   303→	if s.Type != "" {
   304→		m["type"] = string(s.Type)
   305→	}
   306→	if s.Description != "" {
   307→		m["description"] = s.Description
   308→	}
   309→	if len(s.Enum) > 0 {
   310→		m["enum"] = s.Enum
   311→	}
   312→	if s.Items != nil {
   313→		m["items"] = schemaToMap(s.Items)
   314→	}
   315→	if len(s.Properties) > 0 {
   316→		props := map[string]any{}
   317→		for k, v := range s.Properties {
   318→			props[k] = schemaToMap(v)
   319→		}
   320→		m["properties"] = props
   321→	}
   322→	if len(s.Required) > 0 {
   323→		m["required"] = s.Required
   324→	}
   325→	return m
   326→}
